const scoreWithAI = async candidate => {
  try {
    const r = await fetch("/.netlify/functions/ai-score", {
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({
        model:"claude-sonnet-4-20250514",
        max_tokens:900,
        messages:[{role:"user",content:`Anda sistem evaluasi HR profesional untuk ${COMPANY}.

Nilai kandidat ini untuk posisi ${candidate.posisiDilamar}:
- Nama: ${candidate.nama}
- Pendidikan: ${candidate.pendidikan} – ${candidate.jurusan||"-"} (${candidate.universitas||"-"}, IPK: ${candidate.ipk||"N/A"})
- Pengalaman: ${candidate.lamaPengalaman} | Posisi terakhir: ${candidate.posisiTerakhir||"-"} di ${candidate.perusahaanTerakhir||"-"}
- Deskripsi: ${candidate.deskripsiPengalaman||"-"}
- Skill Teknis: ${candidate.skillTeknis||"-"}
- Soft Skills: ${candidate.skillSoft||"-"}
- Bahasa: ${candidate.bahasa||"-"}
- Gaji Diharapkan: ${candidate.gajiDiharapkan||"-"}
- Cover Letter: ${candidate.coverLetter||"-"}

Balas HANYA JSON valid tanpa markdown:
{"totalScore":75,"breakdown":{"pendidikan":70,"pengalaman":80,"kompetensi_teknis":75,"komunikasi":70,"kesesuaian_posisi":80},"kekuatan":["poin1","poin2","poin3"],"kelemahan":["poin1","poin2"],"rekomendasi":"Lanjutkan ke Interview","catatan":"Catatan singkat profesional."}`}]
      })
    });
    const data = await r.json();
    const text = data.content?.[0]?.text?.replace(/```json?|```/g,"").trim()||"{}";
    return { ...JSON.parse(text), status:"done" };
  } catch { return { status:"error" }; }
};

